import axios from 'axios';

const getBaseURL = () => {
  const hostname = window.location.hostname;
  // Jika frontend diakses via localhost, gunakan localhost
  if (hostname === 'localhost' || hostname === '127.0.0.1') {
    return 'http://localhost:5006/api';
  }
  // Untuk akses dari HP (IP yang sama dengan frontend), gunakan IP tersebut
  return `http://${hostname}:5006/api`;
};

const api = axios.create({
    baseURL: getBaseURL(),
    headers: {
        'Content-Type': 'application/json',
    },
    timeout: 10000,
});

// Interceptors tetap seperti semula
api.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        if (config.data instanceof FormData) {
            delete config.headers['Content-Type'];
        }
        return config;
    },
    (error) => Promise.reject(error)
);

api.interceptors.response.use(
    (response) => response,
    (error) => {
        if (error.response?.status === 401) {
            // optional redirect
        }
        return Promise.reject(error);
    }
);

export default api;
